param(    [string]$ProjectRoot = ".",    [string]$Branch = "main",    [string]$RemoteName = "origin",    [string]$RemoteUrl = "https://github.com/Coxf0rd/PetriNet",    [string]$VersionFile = "Cargo.toml",    [string]$CommitSuffix = "")$ErrorActionPreference = "Stop"function Write-Step {    param([string]$Message)    Write-Host ""    Write-Host "==> $Message" -ForegroundColor Cyan}function Fail {    param([string]$Message)    Write-Host ""    Write-Host "ERROR: $Message" -ForegroundColor Red    exit 1}function Ensure-Command {    param([string]$Name)    if (-not (Get-Command $Name -ErrorAction SilentlyContinue)) {        Fail "Command '$Name' not found."    }}function Run-Git {    param(        [Parameter(ValueFromRemainingArguments = $true)]        [string[]]$Args    )    & git @Args    if ($LASTEXITCODE -ne 0) {        Fail "git command failed: git $($Args -join ' ')"    }}function Get-CurrentVersion {    param([string]$CargoTomlPath)    if (-not (Test-Path $CargoTomlPath)) {        Fail "Version file not found: $CargoTomlPath"    }    $content = Get-Content -Raw -Path $CargoTomlPath    $packageBlockRegex = '(?ms)^\[package\].*?(?=^\[|\z)'    $packageBlockMatch = [regex]::Match($content, $packageBlockRegex)    if (-not $packageBlockMatch.Success) {        Fail "Could not find [package] section in $CargoTomlPath"    }    $packageBlock = $packageBlockMatch.Value    $versionRegex = '(?m)^version\s*=\s*"(?<version>\d+\.\d+\.\d+)"\s*$'    $versionMatch = [regex]::Match($packageBlock, $versionRegex)    if (-not $versionMatch.Success) {        Fail "Could not find semantic version in [package] section of $CargoTomlPath"    }    return $versionMatch.Groups["version"].Value}function Get-NextVersion {    param([string]$Version)    $parts = $Version.Split(".")    if ($parts.Count -ne 3) {        Fail "Unsupported version format: $Version"    }    $major = [int]$parts[0]    $minor = [int]$parts[1]    $patch = [int]$parts[2]    $patch = $patch + 1    return "$major.$minor.$patch"}function Set-VersionInCargoToml {    param(        [string]$CargoTomlPath,        [string]$NewVersion    )    $content = Get-Content -Raw -Path $CargoTomlPath    $packageBlockRegex = '(?ms)^\[package\].*?(?=^\[|\z)'    $packageBlockMatch = [regex]::Match($content, $packageBlockRegex)    if (-not $packageBlockMatch.Success) {        Fail "Could not find [package] section in $CargoTomlPath"    }    $packageBlock = $packageBlockMatch.Value    $versionRegex = '(?m)^version\s*=\s*"(?<version>\d+\.\d+\.\d+)"\s*$'    $newPackageBlock = [regex]::Replace(        $packageBlock,        $versionRegex,        ('version = "{0}"' -f $NewVersion),        1    )    if ($newPackageBlock -eq $packageBlock) {        Fail "Failed to update version in $CargoTomlPath"    }    $updated = $content.Substring(0, $packageBlockMatch.Index) + $newPackageBlock + $content.Substring($packageBlockMatch.Index + $packageBlockMatch.Length)    Set-Content -Path $CargoTomlPath -Value $updated -Encoding UTF8}function Ensure-Remote {    param(        [string]$Name,        [string]$Url    )    $existingUrl = ""    try {        $existingUrl = (& git remote get-url $Name 2>$null)        if ($LASTEXITCODE -ne 0) {            $existingUrl = ""        }    } catch {        $existingUrl = ""    }    if ([string]::IsNullOrWhiteSpace($existingUrl)) {        Write-Step "Adding git remote '$Name' -> $Url"        Run-Git remote add $Name $Url    } else {        if ($existingUrl.Trim() -ne $Url.Trim()) {            Write-Step "Updating git remote '$Name' -> $Url"            Run-Git remote set-url $Name $Url        } else {            Write-Step "Git remote '$Name' already points to $Url"        }    }}function Ensure-InsideGitRepo {    $inside = (& git rev-parse --is-inside-work-tree 2>$null)    if ($LASTEXITCODE -ne 0 -or $inside.Trim() -ne "true") {        Fail "Current folder is not a git repository."    }}function Get-CommitMessage {    param(        [string]$Version,        [string]$Suffix    )    if ([string]::IsNullOrWhiteSpace($Suffix)) {        return "v$Version"    }    return "v$Version $Suffix".Trim()}$resolvedRoot = Resolve-Path $ProjectRootSet-Location $resolvedRootWrite-Step "Checking environment"Ensure-Command gitEnsure-InsideGitRepo$cargoTomlPath = Join-Path $resolvedRoot $VersionFileif (-not (Test-Path $cargoTomlPath)) {    Fail "Could not find $VersionFile at $cargoTomlPath"}Write-Step "Ensuring remote configuration"Ensure-Remote -Name $RemoteName -Url $RemoteUrlWrite-Step "Reading current version"$currentVersion = Get-CurrentVersion -CargoTomlPath $cargoTomlPath$newVersion = Get-NextVersion -Version $currentVersion$commitMessage = Get-CommitMessage -Version $newVersion -Suffix $CommitSuffixWrite-Host "Current version: $currentVersion" -ForegroundColor YellowWrite-Host "Next version:    $newVersion" -ForegroundColor GreenWrite-Host "Commit message:  $commitMessage" -ForegroundColor GreenWrite-Step "Updating version in $VersionFile"Set-VersionInCargoToml -CargoTomlPath $cargoTomlPath -NewVersion $newVersionWrite-Step "Saving project changes"Run-Git add .$statusAfterAdd = (& git status --porcelain)if ($LASTEXITCODE -ne 0) {    Fail "Could not read git status."}if ([string]::IsNullOrWhiteSpace($statusAfterAdd)) {    Fail "No changes to commit after version update."}Write-Step "Creating commit"Run-Git commit -m $commitMessageWrite-Step "Pushing to GitHub"Run-Git push $RemoteName $BranchWrite-Host ""Write-Host "Done." -ForegroundColor GreenWrite-Host "Published version: v$newVersion" -ForegroundColor Green